kernel void BFS_1(
    const int* graph_nodes_starting,
    const int* graph_nodes_no_of_edges,
    const int* graph_edges,
    char* graph_mask,
    char* updating_graph_mask,
    const char* graph_visited,
    int* cost,
    int no_of_nodes)
{
    int tid = get_global_id(0);
    if (tid >= no_of_nodes) return;

    if (graph_mask[tid] == 1) {
        graph_mask[tid] = 0;
        int start = graph_nodes_starting[tid];
        int end = start + graph_nodes_no_of_edges[tid];
        for (int i = start; i < end; i++) {
            int id = graph_edges[i];
            if (graph_visited[id] == 0) {
                cost[id] = cost[tid] + 1;
                updating_graph_mask[id] = 1;
            }
        }
    }
}

kernel void BFS_2(
    char* graph_mask,
    char* updating_graph_mask,
    char* graph_visited,
    char* stop_flag,
    int no_of_nodes)
{
    int tid = get_global_id(0);
    if (tid >= no_of_nodes) return;

    if (updating_graph_mask[tid] == 1) {
        graph_mask[tid] = 1;
        graph_visited[tid] = 1;
        stop_flag[0] = 1;
        updating_graph_mask[tid] = 0;
    }
}
